import{_ as i,o as r,c as l,ai as o}from"./chunks/framework.CEhIufms.js";const h=JSON.parse('{"title":"YCup 数学竞赛赛事规则与说明","description":"","frontmatter":{},"headers":[],"relativePath":"guide.md","filePath":"guide.md"}'),a={name:"guide.md"};function e(n,t,s,g,d,$){return r(),l("div",null,[...t[0]||(t[0]=[o('<div><h1 id="ycup-数学竞赛赛事规则与说明" tabindex="-1">YCup 数学竞赛赛事规则与说明 <a class="header-anchor" href="#ycup-数学竞赛赛事规则与说明" aria-label="Permalink to &quot;YCup 数学竞赛赛事规则与说明&quot;">​</a></h1><p>4.9 version</p><h2 id="一、参赛队伍要求" tabindex="-1">一、参赛队伍要求 <a class="header-anchor" href="#一、参赛队伍要求" aria-label="Permalink to &quot;一、参赛队伍要求&quot;">​</a></h2><ol><li><strong>队伍规模</strong>：每支参赛队伍人数限制为 $\\le 3$ 人。每一场的队伍可以变动。</li><li><strong>人员构成</strong>：任意本校同学。</li><li><strong>参赛准则</strong>：参赛队伍需秉持竞技精神，严格遵守诚信参赛原则，禁止作弊、抄袭、违规求助等行为。团队内部保持团结和谐和学术精神。</li></ol><h2 id="二、时间与赛题安排" tabindex="-1">二、时间与赛题安排 <a class="header-anchor" href="#二、时间与赛题安排" aria-label="Permalink to &quot;二、时间与赛题安排&quot;">​</a></h2><ol><li><strong>常规赛时间</strong>：每周二中午 11:50 - 12:30 开展，计划共进行 15 场常规赛，举办地点为 305 教室。</li><li><strong>赛题设置</strong>：每场常规赛包含 9 至 13 道题目（具体数量根据难度动态调整），赛题数量将提前 2 天在比赛群公示，保证所有题目为数学类题目。保证至少有 $20%$ 的题（上取整）不超过校内月考填空题难度，其余题目不超过高联难度。难度有梯度，但不保证按顺序排序。</li><li><strong>组队形式</strong>：三个人可以在赛中以说话、传纸条、摩斯电码、漂流瓶、心灵感应等方式，互相帮助。合理的分工合作是获得更好成绩的好办法。</li><li><strong>出题人规则</strong>：出题人所在队伍不允许参与该场次比赛；出题人队伍的表现分（Perf）按他个人其他场次的平均表现分计算。</li></ol><h2 id="三、赛制设计" tabindex="-1">三、赛制设计 <a class="header-anchor" href="#三、赛制设计" aria-label="Permalink to &quot;三、赛制设计&quot;">​</a></h2><h3 id="_1-答题与反馈机制" tabindex="-1">（1）答题与反馈机制 <a class="header-anchor" href="#_1-答题与反馈机制" aria-label="Permalink to &quot;（1）答题与反馈机制&quot;">​</a></h3><ul><li>每道题的答案限定为复数范围内的数值，且保证只有唯一答案。</li><li>参赛队伍举手向裁判提交答案（写在试卷背面，以<code>[题号],[答案]</code> 的格式指给裁判看，避免告知其他队伍答案），裁判有权拒绝任何除此之外的答案提交形式，裁判仅提供“正确”或“错误”的反馈，不透露具体解题思路或正确答案细节。</li><li>答题队列等待时间不超过 $1$ 分钟，每支参赛队伍可使用<strong>不超过一台</strong>高考允许携带的计算器辅助计算（特殊说明的场次除外），<strong>不可以</strong>携带纸质书籍，<strong>草稿纸自备</strong>。</li><li>选手必须在比赛结束后复原考场，<strong>王以老师</strong>认为没有完成该职责的，可处<strong>罚题或罚时</strong>惩罚。</li><li>每支队伍每题至多提交 10 次，每场比赛至多提交 50 次。</li></ul><h3 id="_2-排名关键字" tabindex="-1">（2）排名关键字 <a class="header-anchor" href="#_2-排名关键字" aria-label="Permalink to &quot;（2）排名关键字&quot;">​</a></h3><ul><li><strong>第一关键字</strong>：过题数量，从大到小排序。统计参赛队伍在单场比赛中成功解决的题目总数。</li><li><strong>第二关键字</strong>：Penalty（罚时），从小到大排序。</li><li><strong>第三关键字</strong>：总提交次数，从小到大排序。</li></ul><p>Penalty 的计算公式为：</p><p>$\\text{Penalty} = \\sum_{\\text{通过的题}} (\\text{通过时间} + 5 \\times \\text{通过的题目的错误尝试次数})$</p><p>其中，“首次通过时间”为题目被首次答对时的时间点（单位：分钟，以比赛开始时刻 12:00 为计时起点）；“错误次数”为队伍提交错误答案的总次数。Penalty 单位为分钟，数值越小表示罚时越少。</p><h3 id="_3-表现分-perf-与-rating-计算" tabindex="-1">（3）表现分（Perf）与 Rating 计算 <a class="header-anchor" href="#_3-表现分-perf-与-rating-计算" aria-label="Permalink to &quot;（3）表现分（Perf）与 Rating 计算&quot;">​</a></h3><ul><li><p><strong>个人单场 Perf 计算</strong>：采用这一场他所在的队伍的 rk（排名）相关公式计算，具体公式形如： $$R = 100 \\times \\frac{n_{teams} - rk + 1}{n_{teams}} + Bonus$$ 其中，第一名队伍的 Bonus 为 50，第二名为 10，第三名为 3。其余队伍为 0。$n_{teams}$ 是所有报名队伍数。假设有六支队伍参赛，则 $R$ 为：$[150, 93.33, 69.67, 50, 33.33, 16.67]$。</p></li><li><p><strong>个人赛季 Rating 计算</strong>：采用他个人所有场次的 Perf 综合计算，未参与设为 0。具体公式形如：假设该选手该赛季所有 Perf 降序排序为 $r_0, r_1, \\dots, r_{m-1}(r_0 \\ge r_1 \\ge \\dots \\ge r_{m-1})$，则他的 Rating 为：$$R = k \\sum_{i=0}^{m-1} (1-k)^i r_i$$ $k$ 会在第三场常规赛结束前确定，暂定为 $\\frac{1}{6}$。</p></li><li><p>根据公式 Rating 只升不降。</p></li></ul><h2 id="四、常规赛奖励规则" tabindex="-1">四、常规赛奖励规则 <a class="header-anchor" href="#四、常规赛奖励规则" aria-label="Permalink to &quot;四、常规赛奖励规则&quot;">​</a></h2><ul><li><strong>全校范围</strong>：冠军（11%），亚军（6%），季军（3%）。</li><li><strong>高一年级范围</strong>：冠军（11%），亚军（6%），季军（3%）。</li><li><strong>高一十二班范围</strong>：冠军（11%），亚军（6%），季军（3%）。</li><li>获得上述奖励需保证参赛至少 50% 的场次。（出题人场次不计）</li><li><strong>冠军次数最多的人</strong>：5%。<strong>亚军次数最多的人</strong>：5%。</li><li><strong>忠诚</strong>（所有搭配过的队友不超过 3 个中 Rating 最高的）：5%。</li><li><strong>独行侠</strong>（全程单人参赛中 Rating 最高的）：5%。</li><li>上述奖励不冲突。</li></ul><p>剩下的选手将按照以下规则分 25%：假设剩余共 $r$ 元（向上取整到整数）。</p><p>采用 <code>mt19937(202812)</code> 作为随机数生成器。</p><p>初始设 $S=0$。遍历 $i=1\\sim n$（其中 $n$ 为未获任何范围内冠亚季军的总人数）。则第 $i$ 人获得区间 $[S,S+\\text{Rating}_i^2)$，$S\\leftarrow S+\\text{Rating}_i^2$。（其中 $\\text{Rating}_i$ 是未获奖的人中 $\\text{Rating}$ 第 $i$ 高的人的 $\\text{Rating}$，四舍五入到整数）</p><p>重复 $r$ 次，每次随机一个在 $[0,S)$ 中的整数。该整数所属的区间所对应的选手获得该 $1$ 元。</p><h2 id="五、报名规则" tabindex="-1">五、报名规则 <a class="header-anchor" href="#五、报名规则" aria-label="Permalink to &quot;五、报名规则&quot;">​</a></h2><ul><li><strong>单场参赛队伍报名</strong>：赛前至少 1 天向高一（12）班 <code>wtc</code> 提交 3 人的姓名和班学号和拟定的队伍名称，以报名参赛队伍，建议尽快报名。</li><li><strong>报名方式</strong>： 加 <code>wtc</code> 微信（微信号：<code>wangtaochun805</code>，年级群昵称：<code>28wtc</code>）或 qq （qq 号：<code>1948735630</code>）了解详情及报名。</li></ul><h2 id="六、其他情况" tabindex="-1">六、其他情况 <a class="header-anchor" href="#六、其他情况" aria-label="Permalink to &quot;六、其他情况&quot;">​</a></h2><ol><li>任何作弊行为会被开除队伍参赛资格，并永久禁止所有团队成员参赛，并上报年级。</li><li>若本规则需要调整，会在赛事群内征求参赛者意见。与校纪校规不冲突的情况下，解释权归裁判组所有。</li></ol><h2 id="七、赞助规则" tabindex="-1">七、赞助规则 <a class="header-anchor" href="#七、赞助规则" aria-label="Permalink to &quot;七、赞助规则&quot;">​</a></h2><ol><li>每场比赛赞助 $5$ 元可以进场观赛，获得纸质题面和答案。</li><li>每道题赞助 $5$ 元可以指定题目背景（需与题目数学内核不冲突）。</li><li>整赛季赞助满 $20$ 元则永久可以获得观赛权益。</li><li>每位同学，至多赞助 $100$ 元。</li><li>所有赞助都会用来发奖金。</li></ol><h2 id="八、出题规则" tabindex="-1">八、出题规则 <a class="header-anchor" href="#八、出题规则" aria-label="Permalink to &quot;八、出题规则&quot;">​</a></h2><ul><li><strong>仅允许高一学生或老师供题出题。必须实名供题（或至少向王以老师提供实名）</strong></li></ul><ol><li>题目难度<strong>必须</strong>符合要求。难度由技术委员会主管裁定。</li><li>题目<strong>必须</strong>不包含堆砌计算器的步骤，所有计算量应从简。</li><li>题面<strong>可以</strong>出现历年数竞原题，但出题人<strong>不可以刻意隐瞒原题</strong>。不接受 AI 提供的形式化题意（美化题面、故事背景是被接受的）。</li><li>过于经典的（任何一个验题人见过的）题目是会被 rejected 的。</li><li>题目应在开赛前<strong>至少 $4$ 天</strong>，以完整形式化题面（则题目背景由技术委员会拟）或完整题面（在不违反校纪校规、不影响题目理解的前提下尽可能尊重出题人题面）交给技术委员会。（无特殊情况地，交给 wtc）</li><li>应给出完整且严谨的题解，包含证明。在开赛前<strong>至少 $1$ 天</strong>，以手写、拍照、<code>markdown</code> 源码均可的方式交给技术委员会。（无特殊情况地，交给 wtc）</li><li>所有题目均会被技术委员会审查后，给出 Accpeted（立即使用）、Deferred（加入备选）、Rejected（不合要求）的评价。</li><li><strong>王以老师</strong>具有对题面的一票否决权。题目中不应该出现违反公序良俗、暴力淫秽的故事背景或相关梗数字作为数据。</li><li><strong>出题人应在比赛现场到场（至少提前 $5$ 分钟）担任裁判，并进行题目答疑。</strong></li><li>出题福利可面谈。</li></ol></div>',1)])])}const u=i(a,[["render",e]]);export{h as __pageData,u as default};
